const GRADES = ["K","1","2","3","4","5"];
const DOMAINS = ["OA","NBT","MD","G"];
const DOMAIN_NAMES = {
  OA:"Operations & Algebraic Thinking",
  NBT:"Number & Operations in Base Ten",
  MD:"Measurement & Data",
  G:"Geometry"
};
const GRADE_LABELS = {
  K:"Kindergarten", "1":"1st Grade", "2":"2nd Grade",
  "3":"3rd Grade", "4":"4th Grade", "5":"5th Grade"
};
const LETTERS = ["A","B","C","D","E"];

function gradeToNum(g) { return g === "K" ? 0 : parseInt(g); }
function numToGrade(n) { return n === 0 ? "K" : String(n); }

// Shuffle array
function shuffle(arr) { return [...arr].sort(() => Math.random() - 0.5); }

// Get questions for a grade+domain
function getQuestions(grade, domain) {
  const pool = QUESTION_BANK[grade]?.[domain] || [];
  return shuffle(pool).slice(0, 5);
}

// ─── ADAPTIVE SCORING ────────────────────────────────────────────────────────
// Fractional grade level:
// Pass at grade G (score ≥ 4): contributes positively
// Fail at grade G (score < 4): contributes partially based on score/5
// The result is the highest grade passed + partial credit toward next
// Each grade level attempt gets a raw decimal score: gradeNum + (score / 5)
// e.g. 3/5 on Grade 3 → 3.6; 4/5 on Grade 2 → 2.8
// Final result = average of the highest-passed attempt and the lowest-failed attempt above it.
// If only passed grades (no ceiling found), use the highest-passed raw score.
// If never passed anything, use the lowest-attempted raw score (may fall below K).
function computeGradeLevel(history) {
  if (!history || history.length === 0) return { label: "Below Kindergarten", numeric: -0.5 };

  // Compute raw decimal for every attempt
  const withRaw = history.map(h => ({
    ...h,
    gradeNum: gradeToNum(h.grade),
    raw: gradeToNum(h.grade) + h.score / 5,
  }));

  const passed = withRaw.filter(h => h.score >= 4);
  const failed = withRaw.filter(h => h.score < 4);

  if (passed.length === 0) {
    // Never passed anything — report the lowest-attempted raw score
    const lowest = withRaw.reduce((min, h) => h.gradeNum < min.gradeNum ? h : min, withRaw[0]);
    const numeric = Math.max(lowest.raw - 1, -0.5); // shift down since they failed it
    return { label: formatGradeLevel(numeric), numeric };
  }

  // Highest-passed attempt
  const topPass = passed.reduce((max, h) => h.gradeNum > max.gradeNum ? h : max, passed[0]);

  // Lowest-failed attempt that sits above the highest pass
  const failedAbove = failed.filter(h => h.gradeNum > topPass.gradeNum);

  if (failedAbove.length === 0) {
    // No ceiling found — at or above the top grade
    if (topPass.gradeNum >= 5) return { label: "5th Grade", numeric: 5 };
    // Only one boundary (floor), use its raw score
    return { label: formatGradeLevel(topPass.raw), numeric: topPass.raw };
  }

  const lowestFail = failedAbove.reduce((min, h) => h.gradeNum < min.gradeNum ? h : min, failedAbove[0]);

  // Average of the two boundary raw scores
  const numeric = (topPass.raw + lowestFail.raw) / 2;
  return { label: formatGradeLevel(numeric), numeric };
}

function formatGradeLevel(numeric) {
  if (numeric <= 0) return "Below Kindergarten";
  // Round to one decimal place
  const rounded = Math.round(numeric * 10) / 10;
  const whole = Math.floor(rounded);
  const dec = Math.round((rounded - whole) * 10);

  if (whole === 0) {
    return dec === 0 ? "Kindergarten" : `Grade K.${dec}`;
  }
  if (dec === 0) return GRADE_LABELS[String(whole)] || `Grade ${whole}`;
  return `Grade ${whole}.${dec}`;
}

// ─── DOMAIN STATE MACHINE ────────────────────────────────────────────────────
// Each grade level: max 5 questions
// Early stop: 2 wrong → fail immediately (stop, go down); 4 right → pass immediately (stop, go up)
function initDomainState(startGrade) {
  return {
    currentGrade: startGrade,
    history: [],
    ceiling: null,
    floor: null,
    done: false,
    resultData: null,
    totalCorrect: 0,
    totalAnswered: 0,
  };
}

// Called when a grade level session ends (either full 5 or early stop)
function concludeGradeLevel(domainState, score, questionsAnswered) {
  const { currentGrade, history, ceiling, floor, totalCorrect = 0, totalAnswered = 0 } = domainState;
  const passed = score >= 4;
  const currentNum = gradeToNum(currentGrade);
  const newHistory = [...history, { grade: currentGrade, score }];
  const newTotalCorrect = totalCorrect + score;
  const newTotalAnswered = totalAnswered + questionsAnswered;

  if (passed) {
    const newFloor = currentGrade;
    const nextNum = currentNum + 1;
    if (nextNum > 5 || ceiling !== null) {
      const resultData = computeGradeLevel(newHistory);
      return { ...domainState, history: newHistory, floor: newFloor, done: true, resultData, totalCorrect: newTotalCorrect, totalAnswered: newTotalAnswered };
    }
    return { ...domainState, history: newHistory, floor: newFloor, currentGrade: numToGrade(nextNum), totalCorrect: newTotalCorrect, totalAnswered: newTotalAnswered };
  } else {
    const newCeiling = currentGrade;
    const prevNum = currentNum - 1;
    if (prevNum < 0 || floor !== null) {
      const resultData = computeGradeLevel(newHistory);
      return { ...domainState, history: newHistory, ceiling: newCeiling, done: true, resultData, totalCorrect: newTotalCorrect, totalAnswered: newTotalAnswered };
    }
    return { ...domainState, history: newHistory, ceiling: newCeiling, currentGrade: numToGrade(prevNum), totalCorrect: newTotalCorrect, totalAnswered: newTotalAnswered };
  }
}

// ─── REPORT HELPERS ──────────────────────────────────────────────────────────
// Returns { proficiency: string, improvement: string }
function domainNarrative(domain, resultData, studentName) {
  const name = studentName || "Your student";
  const area = DOMAIN_NAMES[domain];
  const level = resultData?.label || "—";
  const num = resultData?.numeric ?? 0;
  const tier = num >= 4 ? "high" : num >= 2 ? "mid" : "low";

  const proficiency = {
    OA: {
      high: `${name} demonstrated strong proficiency in ${area}, performing at a ${level} level. They showed confident command of operations, algebraic patterns, and problem-solving strategies — performing at or above grade-level expectations.`,
      mid: `${name} demonstrated developing skills in ${area}, performing at a ${level} level. They showed a working understanding of core operations and number relationships, with some inconsistency across more complex problem types.`,
      low: `${name} is still building foundational skills in ${area}, currently performing at a ${level} level. They demonstrated emerging understanding of basic operations, though application to multi-step or abstract problems was inconsistent.`,
    },
    NBT: {
      high: `${name} demonstrated strong proficiency in ${area}, performing at a ${level} level. They showed solid command of place value, multi-digit computation, and number relationships consistent with above-grade-level expectations.`,
      mid: `${name} demonstrated developing skills in ${area}, performing at a ${level} level. They showed a functional understanding of place value and basic computation, with room to build fluency and consistency across problem types.`,
      low: `${name} is still building foundational skills in ${area}, currently performing at a ${level} level. Core concepts such as place value, number ordering, and basic computation need additional reinforcement before advancing.`,
    },
    MD: {
      high: `${name} demonstrated strong proficiency in ${area}, performing at a ${level} level. They showed the ability to measure accurately, read and interpret data displays, and reason about time, money, and probability at an above-grade level.`,
      mid: `${name} demonstrated developing skills in ${area}, performing at a ${level} level. They showed emerging ability to work with measurement, data, and time, though performance was uneven across the range of concepts in this domain.`,
      low: `${name} is still building foundational skills in ${area}, currently performing at a ${level} level. Skills such as reading a clock, identifying units of measurement, and interpreting simple graphs need focused practice to become reliable.`,
    },
    G: {
      high: `${name} demonstrated strong proficiency in ${area}, performing at a ${level} level. They showed confident understanding of 2D and 3D shapes, transformations, symmetry, and spatial reasoning well beyond typical grade-level expectations.`,
      mid: `${name} demonstrated developing skills in ${area}, performing at a ${level} level. They could identify and classify common shapes and transformations, though performance on spatial reasoning and coordinate-based tasks was less consistent.`,
      low: `${name} is still building foundational skills in ${area}, currently performing at a ${level} level. Basic shape recognition and geometric vocabulary need additional support before more complex concepts can be introduced.`,
    },
  };

  const improvement = {
    OA: {
      high: `To continue growing, ${name} would benefit from exposure to more complex algebraic thinking — such as multi-step word problems, function tables, and introductory equation-solving — to extend their skills into higher grade-level content.`,
      mid: `To strengthen performance in this area, ${name} should focus on building fluency with multiplication and division facts, practicing multi-step problem solving, and working with number patterns and simple algebraic expressions.`,
      low: `Priority areas for growth include strengthening addition and subtraction fluency within 20, building a solid understanding of the relationship between addition and subtraction, and developing comfort with simple missing-number problems.`,
    },
    NBT: {
      high: `To continue growing, ${name} would benefit from work with larger numbers, decimal operations, and fraction-to-decimal conversions — areas that build directly on the strong number sense they have already demonstrated.`,
      mid: `To strengthen performance in this area, ${name} should practice reading and writing multi-digit numbers in multiple forms, work on rounding and estimation strategies, and build fluency with addition and subtraction of larger numbers.`,
      low: `Priority areas for growth include counting and representing two- and three-digit numbers, understanding place value (ones, tens, hundreds), and practicing skip-counting sequences to build number fluency.`,
    },
    MD: {
      high: `To continue growing, ${name} would benefit from more complex measurement and data work — including multi-step measurement conversions, line plots with fractional data, and probability experiments with multiple outcomes.`,
      mid: `To strengthen performance in this area, ${name} should practice telling and writing time to the nearest minute, solving elapsed time problems, counting and comparing money amounts, and reading bar graphs and line plots.`,
      low: `Priority areas for growth include telling time to the hour and half-hour, identifying and comparing coins and their values, ordering objects by length or weight, and reading simple picture graphs and tally charts.`,
    },
    G: {
      high: `To continue growing, ${name} would benefit from exploring coordinate geometry, classifying polygons by their properties, and working with angle measurement and area/perimeter relationships in more complex figures.`,
      mid: `To strengthen performance in this area, ${name} should work on identifying and drawing lines of symmetry, classifying quadrilaterals and triangles by their attributes, and practicing slides, flips, and turns with concrete manipulatives.`,
      low: `Priority areas for growth include naming and sorting 2D shapes by their number of sides and corners, identifying basic 3D shapes, and developing spatial vocabulary (above, below, beside, inside) through hands-on activities.`,
    },
  };

  return {
    proficiency: proficiency[domain][tier],
    improvement: improvement[domain][tier],
  };
}


